-- FARM POSITION TAB
local SpotLeft  = Tabs.Spot:AddLeftGroupbox("Pag-override ng Puwesto ")
local SpotRight = Tabs.Spot:AddRightGroupbox("Key ng Mabilisang Save ")

local overrideLabel = SpotLeft:AddLabel({ Text = "Custom na Puwesto: OFF " })
local savedCFLabel  = SpotLeft:AddLabel({ Text = "Naka-save: wala " })

SpotLeft:AddButton("I-save ang Kasalukuyang Puwesto ", function()
    local char = game.Players.LocalPlayer.Character
    if not char then Library:Notify({Title="Error → Mali", Description="Walang character! ", Duration=3}) return end
    local root = char:FindFirstChild("HumanoidRootPart")
    if not root then Library:Notify({Title="Error → Mali", Description="Walang HumanoidRootPart! ", Duration=3}) return end
    M.setCustomCFrameOverride(root.CFrame)
    local p = root.Position
    savedCFLabel:SetText(string.format("Saved: %.1f, %.1f, %.1f ", p.X, p.Y, p.Z))
    Library:Notify({Title="Naka-save ang Puwesto! ", Description=string.format("%.1f, %.1f, %.1f", p.X, p.Y, p.Z), Duration=4})
end)

SpotLeft:AddButton("I-clear ang Custom na Puwesto ", function()
    M.setCustomCFrameOverride(nil)
    savedCFLabel:SetText("Naka-save: wala ")
    Library:Notify({Title="Na-clear ", Description="Ginagamit ang orihinal na na-capture na puwesto. ", Duration=3})
end)

task.spawn(function()
    while not Library.Unloaded do
        task.wait(0.5)
        overrideLabel:SetText("Custom Position: " .. (M.getCustomCFrameOverride() and "ON " or "OFF "))
    end
end)

local keybindLabel = SpotRight:AddLabel({ Text = "Key ng Mabilisang Save: F " })

SpotRight:AddButton("Itakda ang Key ng Mabilisang Save ", function()
    M.setSettingKeybind(true)
    keybindLabel:SetText("Pindutin ang isang key ngayon... ")
    Library:Notify({Title="Pindutin ang Anumang Key ", Description="Iyon ang key na magsi-save ng puwesto mo. ", Duration=4})
end)

SpotRight:AddButton("I-clear ang Key ng Mabilisang Save ", function()
    M.setTeleportKeybind(nil)
    keybindLabel:SetText("Key ng Mabilisang Save: wala ")
    Library:Notify({Title="Na-clear ang Key ", Description="Walang nakatakdang quick-save key. ", Duration=3})
end)

M.onKeybindSet = function(keyCode)
    keybindLabel:SetText("Quick-Save Key: " .. keyCode.Name .. " ")
end

M.onSpotSaved = function(p)
    savedCFLabel:SetText(string.format("Saved: %.1f, %.1f, %.1f ", p.X, p.Y, p.Z))
end

